/* Fleet empty-state builder (design.md v2 "Component contracts").
 *
 * VENDORED VERBATIM from project-scaffolding. Do NOT edit this file per-app:
 * nothing here varies between apps. Normalized from home-automation's
 * app/webapp/static/icons.js `emptyStateEl` (issue #362), decoupled from that
 * app's button class — the action button is styled by empty-state.css here,
 * not by an app-specific class.
 *
 * Pairs with empty-state.css and the vendored icons/ component (the glyph
 * comes from the inline sprite).
 */

'use strict';

import { icon } from '../icons/icons.js';

/**
 * Build the canonical empty-state block: a muted glyph, a one-line reason,
 * and an optional action button — what every list/grid that can be
 * legitimately empty renders instead of a silent blank area.
 *
 * @param {string} name     sprite glyph name without the `i-` prefix (e.g. 'lightbulb').
 * @param {string} message  the one-line reason (e.g. 'No lights reachable').
 * @param {{actionLabel?: string, onAction?: () => void}} [opts]
 *        both optional; omit for a message-only empty state.
 * @returns {HTMLDivElement}
 */
export function emptyStateEl(name, message, opts) {
  const wrap = document.createElement('div');
  wrap.className = 'empty-state';
  wrap.innerHTML = icon(name, 'empty-state-icon');
  const msg = document.createElement('p');
  msg.className = 'empty-state-message';
  msg.textContent = message;
  wrap.appendChild(msg);
  if (opts && opts.actionLabel) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'empty-state-action';
    btn.textContent = opts.actionLabel;
    if (opts.onAction) btn.addEventListener('click', opts.onAction);
    wrap.appendChild(btn);
  }
  return wrap;
}
